</code></pre> <pre><code># threading — OS-потоки (ограничены GIL для CPU задач, хороши для I/O)
import threading
from threading import Thread, Lock, RLock, Semaphore, Event

results: list[str] = []
lock = Lock()

def worker(name: str) -&gt; None:
    data = do_work(name)
    with lock:
        results.append(data)

threads = [Thread(target=worker, args=(f"t{i}",), daemon=True) for i in range(5)]
for t in threads: t.start()
for t in threads: t.join()

# RLock — reentrant lock
rlock = RLock()
def recursive_work(n: int) -&gt; None:
    with rlock:
        if n &gt; 0: recursive_work(n - 1)

# Event — сигнал между потоками
event = Event()
def producer() -&gt; None:
    time.sleep(1)
    event.set()

def consumer() -&gt; None:
    event.wait()
    print("Got signal!")

# multiprocessing — обходит GIL (настоящая параллельность для CPU)
from multiprocessing import Pool
import multiprocessing as mp

def cpu_heavy(n: int) -&gt; int:
    return sum(i**2 for i in range(n))

with Pool(processes=mp.cpu_count()) as pool:
    results = pool.map(cpu_heavy, [10**6] * 4)

# concurrent.futures — высокоуровневый API (РЕКОМЕНДУЕТСЯ)
from concurrent.futures import ThreadPoolExecutor, ProcessPoolExecutor, as_completed

# I/O задачи — ThreadPoolExecutor
with ThreadPoolExecutor(max_workers=20) as ex:
    futures = {ex.submit(fetch_url, url): url for url in urls}
    for future in as_completed(futures):
        url = futures[future]
        try:
            result = future.result(timeout=5)
        except Exception as e:
            print(f"{url}: {e}")

# CPU задачи — ProcessPoolExecutor
with ProcessPoolExecutor(max_workers=mp.cpu_count()) as ex:
    results = list(ex.map(cpu_heavy, range(8), chunksize=2))

# Python 3.13 — Free-Threaded mode (PEP 703, experimental)
# Установка: python3.13t  или  python --disable-gil
# Отключает GIL → настоящая параллельность в Thread без subprocess
</code></pre>

Swift 6Kotlin 2.xPython 3.13 <pre><code>let x = 42

// Стандартный if-else
if x &gt; 0 { print("positive") }
else if x == 0 { print("zero") }
else { print("negative") }

// if как выражение (Swift 5.9+)
let label = if x &gt; 0 { "positive" } else { "non-positive" }

// guard — ранний выход (избегай pyramid of doom)
func process(value: Int?) {
    guard let v = value, v &gt; 0 else { return }
    // v доступен здесь и до конца функции
    print("Processing \(v)")
}

// guard let shorthand (Swift 5.7+)
func handle(value: Int?) {
    guard let value else { return }
    // value доступен как non-optional
    print(value)
}

// switch — exhaustive (компилятор требует все кейсы)
switch x {
case 0:
    print("zero")
case 1...10:
    print("small")
case let n where n &lt; 0:
    print("negative: \(n)")
case _ where x.isMultiple(of: 2):
    print("large even")
default:
    print("other")
}

// switch как выражение (Swift 5.9+)
let desc = switch x {
    case 0:      "zero"
    case 1...10: "small"
    default:     "large"
}

// Optional binding
let opt: Int? = 42
if let val = opt { print(val) }              // обычный unwrap
