async def create_article(title: str, body: str) -&gt; Article:
    async with AsyncSessionLocal() as session:
        article = Article(title=title, body=body)
        session.add(article)
        await session.commit()
        await session.refresh(article)
        return article

async def get_articles(search: str | None = None) -&gt; list[Article]:
    async with AsyncSessionLocal() as session:
        stmt = select(Article).order_by(Article.created_at.desc())
        if search:
            stmt = stmt.where(Article.title.ilike(f"%{search}%"))
        result = await session.execute(stmt)
        return list(result.scalars().all())

