let ipRef       = Reference(Substring.self)
let methodRef   = Reference(Substring.self)
let pathRef     = Reference(Substring.self)
let statusRef   = Reference(Int.self)
let bytesRef    = Reference(Int.self)

let logRegex = Regex {
    Capture(as: ipRef) {
        Repeat(.digit, 1...3); "."; Repeat(.digit, 1...3); "."
        Repeat(.digit, 1...3); "."; Repeat(.digit, 1...3)
    }
    " - "
    OneOrMore(.word)
    " ["
    OneOrMore(.any, .reluctant)
    "] \""
    Capture(as: methodRef) { OneOrMore(.word) }
    " "
    Capture(as: pathRef)   { OneOrMore(CharacterClass.anyOf(" ").inverted) }
    OneOrMore(.any, .reluctant)
    "\" "
    TryCapture(as: statusRef) {
        Repeat(.digit, count: 3)
    } transform: { Int($0) }
    " "
    TryCapture(as: bytesRef) {
        OneOrMore(.digit)
    } transform: { Int($0) }
}

let logLine = """
    127.0.0.1 - frank [18/Mar/2026:10:15:30 +0200] "GET /api/users HTTP/1.1" 200 1234
    """

if let m = logLine.firstMatch(of: logRegex) {
    print("IP: \(m[ipRef])")                   // "127.0.0.1"
