def create_token(
    user_id: str, role: str,
    expires_in: timedelta = timedelta(hours=1)
) -&gt; str:
    payload = {
        "sub":  user_id,
        "role": role,
        "iat":  datetime.now(UTC),
        "exp":  datetime.now(UTC) + expires_in,
    }
